class Solution(object):
    def largestPrime(self, n):
        # Sieve of Eratosthenes
        sieve = [True] * (n + 1)
        sieve[0] = sieve[1] = False
        for i in range(2, int(n**0.5) + 1):
            if sieve[i]:
                for j in range(i*i, n+1, i):
                    sieve[j] = False
        primes = [i for i in range(2, n+1) if sieve[i]]

        ans = 0
        s = 0
        for p in primes:
            s += p
            if s > n:
                break
            if sieve[s]:
                ans = s
        return ans
